 import javax.annotation.concurrent.GuardedBy;
 import okhttp3.MediaType;
+import okhttp3.OkHttpClient;
 import okhttp3.Request;
 import okhttp3.ResponseBody;
 import okio.Buffer;
@@ -208,7 +209,23 @@ final class OkHttpCall<T> implements Call<T> {
   }

   private okhttp3.Call createRawCall() throws IOException {
-    okhttp3.Call call = callFactory.newCall(requestFactory.create(instance, args));
+    okhttp3.Call.Factory factory = callFactory;
+    retrofit2.http.Timeout timeoutAnnotation = requestFactory.timeout;
+    if (timeoutAnnotation != null && factory instanceof OkHttpClient) {
+      OkHttpClient client = (OkHttpClient) factory;
+      OkHttpClient.Builder builder = client.newBuilder();
+      if (timeoutAnnotation.connectMs() > 0) {
+        builder.connectTimeout(timeoutAnnotation.connectMs(), timeoutAnnotation.unit());
+      }
+      if (timeoutAnnotation.readMs() > 0) {
+        builder.readTimeout(timeoutAnnotation.readMs(), timeoutAnnotation.unit());
+      }
+      if (timeoutAnnotation.writeMs() > 0) {
+        builder.writeTimeout(timeoutAnnotation.writeMs(), timeoutAnnotation.unit());
+      }
+      factory = builder.build();
+    }
+    okhttp3.Call call = factory.newCall(requestFactory.create(instance, args));
     if (call == null) {
       throw new NullPointerException("Call.Factory returned null.");
     }
