diff --git a/retrofit/src/main/java/retrofit2/http/Timeout.java b/retrofit/src/main/java/retrofit2/http/Timeout.java
new file mode 100644
index 0000000..abc1234
--- /dev/null
+++ b/retrofit/src/main/java/retrofit2/http/Timeout.java
@@ -0,0 +1,51 @@
+package retrofit2.http;
+
+import static java.lang.annotation.ElementType.METHOD;
+import static java.lang.annotation.RetentionPolicy.RUNTIME;
+
+import java.lang.annotation.Documented;
+import java.lang.annotation.Retention;
+import java.lang.annotation.Target;
+import java.util.concurrent.TimeUnit;
+
+@Documented
+@Target(METHOD)
+@Retention(RUNTIME)
+public @interface Timeout {
+  int connectMs() default 0;
+  int readMs() default 0;
+  int writeMs() default 0;
+  TimeUnit unit() default TimeUnit.MILLISECONDS;
+}
